#include <bits/stdc++.h>
using namespace std;
int n,mxs[50004],s[50004];
int dist[50004];
vector<int> g[50004];
void dfs(int x){
    s[x]=1;
    int len=g[x].size();
    for(int i=0;i<len;i++)
        if(!s[g[x][i]]){
            dfs(g[x][i]);
            s[x]+=s[g[x][i]];
            mxs[x]=max(mxs[x],s[g[x][i]]);
        }
    mxs[x]=max(mxs[x],n-s[x]);
}
int bfs(int x){
    int sum=0;
    queue<int> q;
    q.push(x),dist[x]=1;
    while(q.size()){
        int f=q.front(),len=g[f].size();
        q.pop();
        for(int i=0;i<len;i++)
            if(!dist[g[f][i]]){
                dist[g[f][i]]=dist[f]+1,sum+=dist[f];
                q.push(g[f][i]);
            }
    }
    return sum;
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<n;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    dfs(1);
    int ans=n,p=0;
    for(int i=1;i<=n;i++)
        if(mxs[i]<ans)
            ans=mxs[i],p=i;
    printf("%d %d",p,bfs(p));
    return 0;
}
